Rule.Source:
import oracle.sql.CLOB;
import com.six.iam.util.TabularData;
import java.util.NoSuchElementException;

// prepare parameters
var rulerunnerOutputProxy = ((rulerunnerOutput == void) || (rulerunnerOutput == null)) ? null : rulerunnerOutput;
var isSlaveExecution = (rulerunnerOutputProxy == null);
var maximumClobSize = (maxClobSize == null) ? 256 : maxClobSize;
var maximumRows = maxRows;

// prepare SQL statement
var statement = new StringBuilder();
statement.append("select ").append(columns).append(" from ").append(tables);
var clauses = Arrays.asList(
	" where ", where,
	" group by ", grouping,
	" having ", having,
	" order by ", ordering
).iterator();
while(clauses.hasNext())
{
	var clause = clauses.next();
	var value = clauses.next();
	if ((value != null) && !value.isEmpty())
	{
		statement.append(clause).append(value);
	}
}

// execute query
if (!isSlaveExecution)
{
	rulerunnerOutputProxy.startTimeMonitoring();
}
var recordCount = 0;
var preparedStatement = context.getJdbcConnection().prepareStatement(statement.toString());
var resultSet = preparedStatement.executeQuery();
var metadata = preparedStatement.getMetaData();
var rows = new Iterator()
{
	private boolean isNext = false;

	public boolean hasNext()
	{
		if (isNext)
		{
			return true;
		}
		if ((maximumRows != null) && (recordCount >= maximumRows))
		{
			if (rulerunnerOutputProxy != null)
			{
				rulerunnerOutputProxy.addMessage("Maximum row count was reached");
			}
			return false;
		}
		if ((rulerunnerOutputProxy != null) && rulerunnerOutputProxy.isTerminationRequested(recordCount == 0))
		{
			return false;
		}
		if (resultSet.next())
		{
			isNext = true;
		}
		return isNext;
	}

	public Map next()
	{
		if (!hasNext())
		{
			throw new NoSuchElementException();
		}
		var record = new HashMap();
		for (var i = 1; i <= metadata.getColumnCount(); ++i)
		{
			var value = resultSet.getObject(i);
			if (value instanceof CLOB)
			{
				var numCharactersLeft = maximumClobSize;
				var buffer = new char[1024];
				var reader = value.getCharacterStream();
				var clob = new StringBuilder();
				while (numCharactersLeft > 0)
				{
					var chunkSize = reader.read(buffer, 0, (numCharactersLeft > buffer.length) ? buffer.length : numCharactersLeft);
					if (chunkSize <= 0)
					{
						break;
					}
					clob.append(buffer, 0, chunkSize);
					numCharactersLeft -= chunkSize;
					if ((numCharactersLeft <= 0) && (reader.read(buffer, 0, 1) > 0))
					{
						clob.append("...");
					}
				}
				value = clob.toString();
			}
			if (value != null)
			{
				record.put(metadata.getColumnLabel(i), value);
			}
		}
		++recordCount;
		isNext = false;
		return record;
	}
};

// return the iterator when invoked from the Generic Query
if (isSlaveExecution)
{
	return rows;
}

// otherwise render output
rulerunnerOutputProxy.write(statement.toString().getBytes("UTF-8"));
rulerunnerOutputProxy.write("<br><br>".getBytes("UTF-8"));
var columns = new ArrayList();
for (var i = 1; i <= metadata.getColumnCount(); ++i)
{
	columns.add(metadata.getColumnLabel(i));
}
var writer = new TabularData(columns, false);
writer.setOutputStream(rulerunnerOutputProxy, "UTF-8");
writer.writeHtmlHeader();
try
{
	while (rows.hasNext())
	{
		writer.writeHtmlRecord(rows.next());
	}
}
finally
{
	writer.writeHtmlFooter();
}
rulerunnerOutputProxy.addMessage(String.format("%d rows in %.02f seconds", recordCount, rulerunnerOutputProxy.getDuration()));
